#include <stdio.h>
int findFloorCeil(int arr[], int n, int k, int *floor, int *ceil) {
    *floor = -1;
    *ceil = -1;
    int low = 0, high = n - 1;
    while (low <= high) {
        int mid = (low + high) / 2;
        if (arr[mid] == k) {
            *floor = arr[mid];
            *ceil = arr[mid];
            return 0;
        } else if (arr[mid] < k) {
            *floor = arr[mid];
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    low = 0;
    high = n - 1;
    while (low <= high) {
        int mid = (low + high) / 2;
        if (arr[mid] >= k) {
            *ceil = arr[mid];
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return 0;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int floor, ceil;
        findFloorCeil(arr, n, k, &floor, &ceil);
        printf("%d %d\n", floor, ceil);
    }
    return 0;
}

